+        obj.insert(extra_key.clone(), extra_val.clone());
+
+        let json_str = Value::Object(obj).to_string();
+        let parsed: CautUsage = serde_json::from_str(&json_str).expect("parse with extra field");
+
+        prop_assert!(
+            parsed.extra.contains_key(&extra_key),
